import java.util.Scanner;
public class Main {
    static final int MAXN = 100005;
    static int[] tree = new int[4 * MAXN];
    public static void build(int[] arr, int node, int start, int end) {
        if (start == end) {
            tree[node] = arr[start];
        } else {
            int mid = (start + end) / 2;
            build(arr, 2 * node, start, mid);
            build(arr, 2 * node + 1, mid + 1, end);
            tree[node] = Math.min(tree[2 * node], tree[2 * node + 1]);
        }
    }
    public static int query(int node, int start, int end, int l, int r) {
        if (r < start || end < l) return Integer.MAX_VALUE;
        if (l <= start && end <= r) return tree[node];
        int mid = (start + end) / 2;
        return Math.min(query(2 * node, start, mid, l, r), query(2 * node + 1, mid + 1, end, l, r));
    }
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int n = scanner.nextInt();
        int[] arr = new int[n];
        for (int i = 0; i < n; i++) arr[i] = scanner.nextInt();
        build(arr, 1, 0, n - 1);
        int q = scanner.nextInt();
        while (q-- > 0) {
            int l = scanner.nextInt(), r = scanner.nextInt();
            l--; r--;
            if (l <= r) System.out.println(query(1, 0, n - 1, l, r));
            else System.out.println(Math.min(query(1, 0, n - 1, l, n - 1), query(1, 0, n - 1, 0, r)));
        }
    }
}

