const readline = require('readline');
const rl = readline.createInterface({
    input: process.stdin,
    output: process.stdout
});
const lines = [];
rl.on('line', (input) => {
    lines.push(input);
});
rl.on('close', () => {
    let l = 0;
    const nextLine = () => lines[l++];
    const nextInt = () => parseInt(nextLine());
    const nextInts = () => nextLine().split(' ').map((x) => parseInt(x));
    const MAXN = 100005;
    const tree = new Array(4 * MAXN).fill(Infinity);
    function build(arr, node, start, end) {
        if (start === end) {
            tree[node] = arr[start];
        } else {
            const mid = Math.floor((start + end) / 2);
            build(arr, 2 * node, start, mid);
            build(arr, 2 * node + 1, mid + 1, end);
            tree[node] = Math.min(tree[2 * node], tree[2 * node + 1]);
        }
    }
    function query(node, start, end, l, r) {
        if (r < start || end < l) return Infinity;
        if (l <= start && end <= r) return tree[node];
        const mid = Math.floor((start + end) / 2);
        return Math.min(query(2 * node, start, mid, l, r), query(2 * node + 1, mid + 1, end, l, r));
    }
    const n = nextInt();
    const arr = nextInts();
    build(arr, 1, 0, n - 1);
    const q = nextInt();
    for (let i = 0; i < q; i++) {
        const [l, r] = nextInts();
        let left = l - 1;
        let right = r - 1;
        if (left <= right) console.log(query(1, 0, n - 1, left, right));
        else console.log(Math.min(query(1, 0, n - 1, left, n - 1), query(1, 0, n - 1, 0, right)));
    }
});

